for rashi in remaining_rashis:
    RASHIFAL_30[rashi] = generic_days


def upload():
    print("🚀 Uploading to Firestore...")
    for rashi_name, days in RASHIFAL_30.items():
        for i, day_data in enumerate(days):
            day_num = str(i + 1)
            db.collection("rashifal") \
              .document(rashi_name) \
              .collection("days") \
              .document(day_num) \
              .set(day_data)
            print(f"  ✅ {rashi_name} → Day {day_num}")
    print("\n🎉 Upload complete! All 12 rashis × 30 days uploaded.")


if __name__ == "__main__":
    upload()